let triggerTime = parseFloat(msg.payload); // Zeit in Sekunden aus dem input
let timerId = flow.get("timerId") || null; // Holen des Timer-IDs aus dem Flow-Kontext
let endTime = flow.get("endTime") || Date.now() + triggerTime * 1000; // Endzeit aus Flow-Kontext oder neu berechnen
const triggerIntervalSeconds = Math.max(1, triggerTime || 1);

function buildTriggerMeta() {
    return {
        trigger: {
            intervalSeconds: triggerIntervalSeconds,
            intervalMs: triggerIntervalSeconds * 1000
        }
    };
}

// Bestehenden Timer löschen, falls vorhanden
if (timerId) {
    clearInterval(timerId);
}

// Funktion zur Aktualisierung des Node-Status
function updateCountdown() {
    let remainingTime = Math.ceil((endTime - Date.now()) / 1000);
    if (remainingTime > 0) {
        node.status({ fill: "red", shape: "ring", text: `Trigger in ${remainingTime}s` });
    } else {
        node.status({ fill: "green", shape: "dot", text: "Triggered" });
        endTime = Date.now() + triggerIntervalSeconds * 1000; // Neu berechnen des Endzeitpunkts für kontinuierliche Wiederholungen
        node.send({
            payload: true,
            meta: buildTriggerMeta()
        }); // Sende 'true' bei Ablauf des Timers
    }
}

// Setzen des Intervall-Timers
timerId = setInterval(() => {
    updateCountdown();
}, 1000); // Jede Sekunde aktualisieren

// Speichern des Timer-IDs und des Endzeitpunkts im Flow-Kontext
flow.set("timerId", timerId);
flow.set("endTime", endTime);
flow.set("triggerIntervalSeconds", triggerIntervalSeconds);

// Initialer Aufruf zur Statusaktualisierung
updateCountdown();

return null; // Keine direkte Nachrichtenausgabe

// Definier Funktion zur Erstellung der Log-Nachricht
function createLogFileMsg(
    dtuState,
    invStateProducing,
    invStateReachable,
    statusZeroInjection,
    pwrConsumption,
    pwrSecondSource,
    socLevelBattery,
    setPercentMsg,
    turnOnMsg,
    turnOffMsg,
    debugMsg
) {
    const now = new Date();
    const formattedTime = now.toLocaleString("de-DE", { hour12: false }); // Formatiert Zeit als 'Tag.Monat.Jahr Stunden:Minuten:Sekunden'

    // Konvertiert Zahlenwerte zu Strings mit Komma als Dezimaltrennzeichen
    const formattedPwrConsumption = pwrConsumption.toLocaleString("de-DE");
    const formattedPwrSecondSource = pwrSecondSource.toLocaleString("de-DE");

    return {
        payload: {
            time: formattedTime,
            dtuState: dtuState,
            invStateProducing: invStateProducing,
            invStateReachable: invStateReachable,
            statusZeroInjection: statusZeroInjection,
            pwrConsumption: formattedPwrConsumption,
            pwrSecondSource: formattedPwrSecondSource,
            socLevelBattery: socLevelBattery,
            setPercentMsg: setPercentMsg ? setPercentMsg.payload : null,
            turnOnMsg: turnOnMsg ? turnOnMsg.payload : null,
            turnOffMsg: turnOffMsg ? turnOffMsg.payload : null,
            debugMsg: debugMsg.payload
        }
    };
}

// Definiert min und max Prozentwerte für die DTU-Ausgangsleistung
const maxOutputPowerInv = parseFloat(msg.payload.maxOutputPowerInv); // Maximale Ausgangsleistung des Wechselrichters in Watt
const pwrSteps = maxOutputPowerInv / 100; // Berechnet die Leistung pro Prozent
const minOutputZeroInjection = parseFloat(msg.payload.minOutputZeroInjection); // Minimale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputZeroInjection = parseFloat(msg.payload.maxOutputZeroInjection); // Maximale Leistung in Prozent bei aktivierter Nulleinspeisung
const maxOutputAtFullSoc = parseFloat(msg.payload.maxOutputAtFullSoc); // Maximale Ausgangsleistung in Prozent bei vollem Batterie-SoC
const staticInverterOutputPower = parseFloat(msg.payload.staticInverterOutputPower); // Voreingestellte Ausgangsleistung, wenn Nulleinspeisung deaktiviert ist
const minPowerInverter = minOutputZeroInjection * pwrSteps; // Berechnet die minimale Leistung in Watt, basierend auf dem Prozentwert und den Leistungsschritten

// Definiert Schwellenwerte für den Batterie-SoC
const offThresholdInv = parseFloat(msg.payload.offThresholdInv); // Batterie-SoC-Schwelle zum Ausschalten des Wechselrichters
const onThresholdInv = parseFloat(msg.payload.onThresholdInv); // Batterie-SoC-Schwelle zum Einschalten des Wechselrichters

// Extrahiert Daten aus msg.payload für Steuerungsentscheidungen
const dtuState = msg.payload.dtuState; // Der aktuelle Betriebszustand der DTU (Datenübertragungseinheit)
const pwrSecondSource = parseFloat(msg.payload.pwrSecondSource); // Leistung der zweiten Energiequelle in Watt
const pwrConsumption = parseFloat(msg.payload.pwrConsumption); // Aktueller Gesamtstromverbrauch in Watt
const invStateProducing = msg.payload.invStateProducing; // Gibt an, ob der Wechselrichter aktuell Strom produziert
const invStateReachable = msg.payload.invStateReachable; // Verfügbarkeitsstatus des Wechselrichters
const socLevelBattery = parseFloat(msg.payload.socLevelBattery); // Der aktuelle Ladezustand der Batterie in Prozent
const statusZeroInjection = msg.payload.statusZeroInjection; // Aktueller Status der Nulleinspeisung ('on' oder 'off')

// Entscheidungslogik für die Ausgabe der Befehle basierend auf dem Zustand und den Messdaten
let setPercentMsg = null;
let turnOnMsg = null;
let turnOffMsg = null;
let debugMsg = null;

// Steuerung basierend auf dem Status der Nulleinspeisung
if (statusZeroInjection !== "on") {
    if (invStateProducing === "on") {
        setPercentMsg = { payload: staticInverterOutputPower };
        debugMsg = { payload: "Nulleinspeisung deaktiviert, statische Leistung angewendet" };
    } else {
        debugMsg = { payload: "Nulleinspeisung deaktiviert, Wechselrichter aus" };
    }
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: "Nulleinspeisung aktiviert" };
}

// Überprüft die Erreichbarkeit und Betriebsbereitschaft der Systemkomponenten
if (dtuState !== "on" || invStateReachable !== "on") {
    debugMsg = { payload: `DTU offline oder Wechselrichter nicht erreichbar` };
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [null, null, null, debugMsg, logFileMsg];
} else {
    debugMsg = { payload: `DTU und Wechselrichter sind online` };
}

// Berechnet die erforderliche Leistungskorrektur basierend auf dem aktuellen Verbrauch und der Zweitquelle
let powerDifference = pwrConsumption - pwrSecondSource;

// Steuerung des Wechselrichters basierend auf dem Batterie-SoC und der Differenzleistung
if (socLevelBattery <= offThresholdInv && invStateProducing === "on") {
    turnOffMsg = { payload: "OFF" };
    const logFileMsg = createLogFileMsg(
        dtuState,
        invStateProducing,
        invStateReachable,
        statusZeroInjection,
        pwrConsumption,
        pwrSecondSource,
        socLevelBattery,
        setPercentMsg,
        turnOnMsg,
        turnOffMsg,
        debugMsg
    );
    return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];
} else {
    // Zuerst wird überprüft, ob der Wechselrichter Strom produziert
    if (invStateProducing === "on") {
        if (powerDifference < minPowerInverter) {
            // Sendet ein Signal, um den Wechselrichter auszuschalten, falls die Differenzleistung unter dem Mindestniveau liegt
            turnOffMsg = { payload: "OFF" };
        } else {
            // Berechnet den erforderlichen Leistungsprozentsatz, wenn keine Ausschaltanforderung vorliegt
            let requiredPercent = Math.floor(powerDifference / pwrSteps);
            let effectiveMaxOutput =
                socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
            requiredPercent = Math.max(
                minOutputZeroInjection,
                Math.min(requiredPercent, effectiveMaxOutput)
            );
            setPercentMsg = { payload: requiredPercent };
        }
    } else if (socLevelBattery >= onThresholdInv && powerDifference >= minPowerInverter) {
        // Überprüft, ob der Batterie-SoC oberhalb des Schwellenwertes liegt und die Differenzleistung ausreichend ist
        let requiredPercent = Math.floor(powerDifference / pwrSteps);
        let effectiveMaxOutput =
            socLevelBattery === 100 ? maxOutputAtFullSoc : maxOutputZeroInjection;
        requiredPercent = Math.max(
            minOutputZeroInjection,
            Math.min(requiredPercent, effectiveMaxOutput)
        );
        setPercentMsg = { payload: requiredPercent };
        turnOnMsg = { payload: "ON" };
    } else {
        // Keine Aktion erforderlich, da der Wechselrichter aus ist und die Bedingungen zum Einschalten nicht erfüllt sind
        debugMsg = {
            payload: "Wechselrichter bleibt aus - Bedingungen zum Einschalten nicht erfüllt"
        };
    }
}

const logFileMsg = createLogFileMsg(
    dtuState,
    invStateProducing,
    invStateReachable,
    statusZeroInjection,
    pwrConsumption,
    pwrSecondSource,
    socLevelBattery,
    setPercentMsg,
    turnOnMsg,
    turnOffMsg,
    debugMsg
);
// Rückgabe der Steuerbefehle
return [setPercentMsg, turnOnMsg, turnOffMsg, debugMsg, logFileMsg];

// 1. DATA RETRIEVAL
function getFirstFinite(values, fallback = 0) {
    for (const value of values) {
        if (Number.isFinite(value)) {
            return value;
        }
    }

    return fallback;
}

const gridPower = getFirstFinite([msg.data?.grid?.power], 0);
const maxChargePower = getFirstFinite(
    [msg.data?.battery?.chargeHardwareMaxPower, msg.data?.battery?.chargeMaxPower],
    800
);
const batteryInflow = getFirstFinite([msg.data?.battery?.chargePower], 0);
const calculatedDemand = getFirstFinite(
    [msg.derived?.demand?.defensiveTarget, msg.adjustment?.defensiveTarget],
    0
);
const liveSolarPower = getFirstFinite(
    [msg.derived?.solar?.livePower, msg.adjustment?.solarPower, msg.data?.solar?.totalPower],
    0
);
const stableSolarPower = getFirstFinite(
    [msg.derived?.solar?.averagePower, msg.adjustment?.solarAveragePower, liveSolarPower],
    liveSolarPower
);
const solarLiveBlend = 0.35; // Pull part of the live solar into the stable value on cloudy days
const effectiveSolarPower = Math.max(
    stableSolarPower,
    liveSolarPower * solarLiveBlend + stableSolarPower * (1 - solarLiveBlend)
);
const soc = getFirstFinite([msg.data?.battery?.soc], 0);
const minSoc = getFirstFinite([msg.data?.battery?.minSoc], 15);
const currentSetInflow = getFirstFinite([msg.data?.battery?.chargeSetpoint], 0);
const totalProduced = getFirstFinite([msg.data?.solar?.totalPower], 0);
const demandTiming = msg.meta?.sensorTiming?.demand;
const demandTimingThresholds = msg.meta?.sensorTiming?.thresholds || {};
const demandConfidence = demandTiming?.confidence;
const reliableDemandConfidence = Number.isFinite(demandTimingThresholds.reliableConfidence)
    ? demandTimingThresholds.reliableConfidence
    : 0.7;
const gridTimingReading = demandTiming?.sensors?.grid;

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
const targetBuffer = 30; // Aim for 30W import
const maxInverterPower = 1200; // the Inverter limit
const minSustain = 50; // Keep charging circuit active
const exportTolerance = 5; // Ignore tiny meter jitter, react to real export quickly
const exportBoostFactor = 1.25; // Compensate for meter/inverter latency when exporting

// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects that there is more solar power than demand,
// e.g. 1000W (solar) - 300W (demand) + 30W buffer = 730W to charge
//      300W (solar) - 350W (demand) + 30W buffer = -20W hardly necessary to charge
//      200W (solar) - 200W (demand) + 30W buffer = 30W to charge
//        0W (solar) - 200W (demand) + 30W buffer = -170W do not charge
//        1W (solar) - 201W (demand) + 30W buffer = -170W stop charging
//  --- SAFETY RULES & CLAMPING
let clampReason = "None";
let ruleApplied = "None";
const isExporting = gridPower < -exportTolerance;
let lastCommand = context.get("lastCommand") || 0;
const lastDemandEstimate = context.get("lastDemandEstimate");

const demandSnapshotReliable =
    !Number.isFinite(demandConfidence) || demandConfidence >= reliableDemandConfidence;
const gridSnapshotReliable = gridTimingReading?.isValid !== false;
const shouldFreezeCommand = !gridSnapshotReliable || !Number.isFinite(gridPower);

if (shouldFreezeCommand) {
    const holdCommand = Math.round(Math.max(lastCommand, currentSetInflow, batteryInflow, 0));
    node.status({
        fill: "green",
        shape: "ring",
        text: `Stable @ ${holdCommand}W`
    });
    return null;
}

function clampChargeCommand(value) {
    let clampedValue = value;

    if (clampedValue > maxInverterPower) {
        clampedValue = maxInverterPower;
        clampReason = "Inverter Max";
    }
    if (clampedValue > maxChargePower) {
        clampedValue = maxChargePower;
        clampReason = "Battery Max";
    }
    if (clampedValue < 0) {
        clampedValue = 0;
        ruleApplied = "Floor (0W)";
    }

    return clampedValue;
}

function emitCommand({ command, targetCharge, theoreticalSurplus, statusFill, statusText }) {
    const roundedCommand = Math.round(command);
    const roundedTarget = Math.round(targetCharge);
    const roundedSurplus = Math.round(theoreticalSurplus);
    const delta = Math.abs(command - lastCommand);

    msg.adjustment.command = roundedCommand;
    msg.adjustment.grid = gridPower;
    msg.derived = msg.derived || {};
    msg.derived.solar = msg.derived.solar || {};
    msg.derived.energy = msg.derived.energy || {};
    msg.derived.solar.effectivePower = Math.round(effectiveSolarPower);
    msg.derived.energy.theoreticalSurplus = roundedSurplus;
    msg.action = msg.action || {};
    msg.action.charge = msg.action.charge || {};
    msg.action.charge.targetPower = roundedTarget;
    msg.action.charge.commandPower = roundedCommand;
    msg.action.charge.ruleApplied = ruleApplied;
    msg.action.charge.clampReason = clampReason;
    context.set("lastCommand", command);
    context.set("lastGridPower", gridPower);
    context.set(
        "lastDemandEstimate",
        getFirstFinite([demandTiming?.currentEstimate, msg.adjustment?.currentDemandEstimate], 0)
    );

    const insights = {
        payload: {
            timestamp: new Date().toISOString(),
            efficiency: {
                gridExport: gridPower < 0 ? Math.abs(gridPower) : 0,
                isLeaking: isExporting
            },
            calculation: {
                theoreticalSurplus: roundedSurplus,
                targetCharge: roundedTarget,
                finalCommand: roundedCommand
            },
            constraints: {
                clamp: clampReason,
                rule: ruleApplied,
                delta: Math.round(delta)
            },
            sensors: {
                solarLive: liveSolarPower,
                solarStable: stableSolarPower,
                solarEffective: Math.round(effectiveSolarPower),
                demand: calculatedDemand,
                grid: gridPower,
                soc: soc
            }
        }
    };

    node.status({
        fill: statusFill,
        shape: "dot",
        text: statusText
    });

    return [msg, insights];
}

if (!demandSnapshotReliable) {
    ruleApplied = "Low-Confidence Grid Steering";

    const baseCommand = Math.max(lastCommand, currentSetInflow, 0);
    const currentDemandEstimate = getFirstFinite(
        [demandTiming?.currentEstimate, msg.adjustment?.currentDemandEstimate],
        0
    );
    const demandDelta = Number.isFinite(lastDemandEstimate)
        ? currentDemandEstimate - lastDemandEstimate
        : null;
    let targetCharge = baseCommand;

    if (isExporting) {
        const exportCorrection = Math.abs(gridPower) + targetBuffer;
        const commandAlreadyAheadOfMeasuredInflow = currentSetInflow > batteryInflow + targetBuffer;

        if (commandAlreadyAheadOfMeasuredInflow && Math.abs(gridPower) <= targetBuffer) {
            targetCharge = baseCommand;
        } else if (maxChargePower > 800 || Math.abs(gridPower) <= targetBuffer * 2) {
            targetCharge = baseCommand + exportCorrection;
        }
    } else if (gridPower > targetBuffer) {
        const importCorrection = gridPower - targetBuffer;
        const demandSpike = currentDemandEstimate - calculatedDemand;
        const isShortDemandPeak =
            demandDelta !== null &&
            demandDelta > 0 &&
            demandSpike > 100 &&
            calculatedDemand <= lastDemandEstimate + targetBuffer &&
            gridPower <= targetBuffer * 2;
        if (isShortDemandPeak) {
            targetCharge = baseCommand;
        } else {
            const demandCorrection =
                demandDelta !== null && demandDelta > 0 ? demandDelta * 2 : importCorrection;

            targetCharge = baseCommand - Math.max(importCorrection, demandCorrection);
        }
    }

    const smoothedCommand = clampChargeCommand(targetCharge);
    return emitCommand({
        command: smoothedCommand,
        targetCharge,
        theoreticalSurplus: effectiveSolarPower - calculatedDemand,
        statusFill: isExporting ? "yellow" : "green",
        statusText: `Cmd: ${Math.round(smoothedCommand)}W | Rule: ${ruleApplied} | Grid: ${Math.round(
            gridPower
        )}W`
    });
}

// 3. THE CALCULATION (Grid-Anchor)
const theoreticalSurplus = effectiveSolarPower - calculatedDemand;
let targetCharge = Math.max(0, theoreticalSurplus + targetBuffer);

// If we are exporting, add an explicit anti-export correction on top of the
// stable surplus target so slight leaks are not ignored.
if (isExporting) {
    const exportIntensity = Math.abs(gridPower);
    const exportBoost = Math.round(exportIntensity * exportBoostFactor);
    targetCharge = Math.max(targetCharge, currentSetInflow + exportBoost);
    ruleApplied = "Anti-Export";
}

// 4. SANITY CHECKS & SUSTAIN
// If solar production is > 150W, we keep the charging circuit 'warm' at 50W,
// even if the house is currently importing from the grid.
const productionThreshold = 150; // Adjust this based on your 'sunny enough' preference

if (totalProduced > productionThreshold && targetCharge < minSustain) {
    targetCharge = minSustain;
    ruleApplied = "Sustain (Production)";
    // If we are sustained at 50W, but we are still exporting, nudge the charge
    // above sustain to swallow the leak.
    if (isExporting) {
        targetCharge = Math.max(targetCharge, minSustain + Math.abs(gridPower));
        ruleApplied = "Sustain + Anti-Leak";
    }
}

// Keep the Solar Ceiling safety
const solarCeiling = theoreticalSurplus + 100;
if (targetCharge > solarCeiling && !isExporting) {
    // But we don't want to charge from the grid!
    // If targetCharge is Sustain(50) but theoreticalSurplus is -58,
    // we need to decide if we 'waste' 50W of grid power to keep the battery warm.
    // Let's allow it ONLY if the deficit isn't massive.
    if (theoreticalSurplus < -200) {
        targetCharge = 0; // House is too hungry, give up on sustain.
    }
}

// Minimum Sustain: If sun is out, stay at 50W even if demand is high
if (theoreticalSurplus > 10 && targetCharge < minSustain) {
    targetCharge = minSustain;
}

// Hard floor
if (targetCharge < 0) targetCharge = 0;

// 5. DYNAMIC SMOOTHING (Slew Rate)
// Instead of a fixed Alpha, we use a "Fast-Up, Slow-Down" approach.
let finalAlpha;
if (isExporting) {
    // CRITICAL: If we are exporting, we jump to the target IMMEDIATELY
    finalAlpha = 1.0;
} else if (targetCharge > lastCommand) {
    // If we are increasing charge (but not leaking), move fast
    finalAlpha = 0.9;
} else {
    // If we are decreasing charge, move slowly to stay "warm"
    finalAlpha = 0.2;
}
let smoothedCommand = targetCharge * finalAlpha + lastCommand * (1 - finalAlpha);

// Rule: Minimum SoC Recovery
if (soc <= minSoc && totalProduced >= 150) {
    const recoveryCharge = totalProduced / 2;
    if (smoothedCommand < recoveryCharge) {
        smoothedCommand = recoveryCharge;
        ruleApplied = "SoC Recovery";
    }
}

smoothedCommand = clampChargeCommand(smoothedCommand);

// 7. CYCLE GUARD (Deadband)
// If we are stable and not exporting, don't update if change is tiny
const delta = Math.abs(smoothedCommand - lastCommand);
if (delta < 5 && gridPower >= 0 && batteryInflow === 0) {
    node.status({ fill: "green", shape: "ring", text: `Stable @ ${Math.round(smoothedCommand)}W` });
    return null;
}

// 8. OUTPUTS & PERSISTENCE
return emitCommand({
    command: smoothedCommand,
    targetCharge,
    theoreticalSurplus,
    statusFill: isExporting ? "red" : "green",
    statusText: `Cmd: ${Math.round(smoothedCommand)}W | Clamp: ${clampReason} | Export: ${Math.round(
        gridPower
    )}W`
});

function getFirstFinite(values, fallback = 0) {
    for (const value of values) {
        if (Number.isFinite(value)) {
            return value;
        }
    }

    return fallback;
}

const data = msg.data || {};
const derived = msg.derived || {};

const sunAbove = data.sun?.aboveHorizon === true;
const soc = getFirstFinite([data.battery?.soc], 0);
const minimalCharge = getFirstFinite([data.battery?.minSoc], 0);
const totalSolarRemaining = getFirstFinite([data.forecast?.solarRemainingWh], 0);
const solarPower = getFirstFinite([derived.solar?.livePower], 0);

let toCharge = null;
let toDischarge = null;

/**
 * DECISION LOGIC:
 * Switch to NIGHT/DISCHARGE mode only if:
 * - Sun is down OR the total remaining forecast is negligible (< 50Wh)
 * - AND we aren't in a "Low Battery" state where we should strictly wait for sun.
 */
const isSolarDayOver = !sunAbove || totalSolarRemaining < 50;
const batteryHasReserve = soc > minimalCharge;
const nightLowSocBlock = isSolarDayOver && !batteryHasReserve;

msg.action = msg.action || {};
msg.action.decision = {
    isSolarDayOver,
    batteryHasReserve,
    nightLowSocBlock,
    dischargeStopThreshold: minimalCharge
};
msg.action.battery = msg.action.battery || {};
msg.action.battery.discharge = msg.action.battery.discharge || {};
msg.action.battery.discharge.stopRequested = nightLowSocBlock;
msg.action.battery.discharge.blockedByLowSoc = nightLowSocBlock;

if (isSolarDayOver && batteryHasReserve) {
    toDischarge = msg;
    node.status({
        fill: "blue",
        shape: "dot",
        text: `Discharge - Night, remaing solar ${totalSolarRemaining}Wh, Solar Day is Over: ${isSolarDayOver}, battery has res: ${batteryHasReserve}`
    });
} else if (solarPower > 0) {
    toCharge = msg;
    node.status({
        fill: "yellow",
        shape: "dot",
        text: `Charge - Day/Solar: remaing solar ${totalSolarRemaining}Wh`
    });
} else {
    node.status({
        fill: "red",
        shape: "dot",
        text: `Empty Battery, no solar power: ${solarPower}W, solar forecast ${totalSolarRemaining}Wh, battery soc: ${soc}`
    });
}

return [toCharge, toDischarge];

const map = msg.payload;
const adj = msg.adjustment; // Contains .command, .requiredChange, and .grid

// 1. DATA EXTRACTION FROM MAP
const soc = parseFloat(map["sensor.solarflow_800_pro_electric_level"]?.state) || 0;
const maxSoc = parseFloat(map["number.solarflow_800_pro_soc_set"]?.state) || 100; // Your threshold
const currentInflow = parseFloat(map["sensor.solarflow_800_pro_grid_input_power"]?.state) || 0;
const currentSetInflow = parseFloat(map["number.solarflow_800_pro_input_limit"]?.state) || 0;
const maxChargeHardware =
    parseFloat(map["sensor.solarflow_800_pro_charge_max_limit"]?.attributes?.max) || 800;

// 2. CORE CALCULATION
// adj.command is negative when we have to charge the battery with solar power
let targetCharge = Math.abs(adj.command);

// Add a safety check: If Actual and Set are miles apart (e.g. communication error),
// fallback to a more conservative average.
// To INCREASE charging, we subtract the negative error (e.g., 100 - (-200) = 300)
const gap = Math.abs(currentSetInflow - currentInflow);
if (gap > 100) {
    // Something is wrong (communication lag or manual override)
    // Fallback to Actual to be safe
}

// 3. APPLY RULES & SAFETY
let reason = "Adjusting normally";

// Check: Battery Full
if (soc + 1.1 > maxSoc) {
    targetCharge = 0;
    reason = "BATTERY_FULL_OVERFLOW";
} else if (targetCharge > maxChargeHardware) {
    reason = "MAX_CHARGE_OVERFLOW";
}

// Rule: Hardware Limits
targetCharge = Math.max(0, Math.min(maxChargeHardware, targetCharge));

// 4. LOGGING & OUTPUT
const logMsg = {
    payload: {
        time: new Date().toLocaleString("de-DE"),
        grid: adj.grid,
        soc: soc,
        targetCharge: Math.round(targetCharge),
        reason: reason
    }
};

// Only trigger the hardware if the change is significant (> 10W)
let hardwareCmd = null;
