            spreadMs: null,
            averageAgeMs: null
        };
    }

    const minAgeMs = Math.min(...ages);
    const maxAgeMs = Math.max(...ages);
    const totalAgeMs = ages.reduce((sum, ageMs) => sum + ageMs, 0);

    return {
        minAgeMs,
        maxAgeMs,
        spreadMs: maxAgeMs - minAgeMs,
        averageAgeMs: totalAgeMs / ages.length
    };
}

function clamp01(value) {
    return Math.max(0, Math.min(1, value));
}

function calculateConfidence(ageStats, thresholds, forceZero = false) {
    if (forceZero) {
        return 0;
    }

    const ageConfidence =
        ageStats.maxAgeMs === null ? 1 : clamp01(1 - ageStats.maxAgeMs / thresholds.maxSensorAgeMs);
    const spreadConfidence =
        ageStats.spreadMs === null
            ? 1
            : clamp01(1 - ageStats.spreadMs / thresholds.maxSensorSpreadMs);

    return Math.min(ageConfidence, spreadConfidence);
}

function blendWithFallback(liveValue, fallbackValue, confidence) {
    return liveValue * confidence + fallbackValue * (1 - confidence);
}

const triggerIntervalSeconds =
    msg.meta?.trigger?.intervalSeconds || flow.get("triggerIntervalSeconds") || 20;
const historyWindowSeconds = 5 * 60;
const historySamples = Math.max(15, Math.ceil(historyWindowSeconds / triggerIntervalSeconds));
const timingThresholds = {
    maxSensorAgeMs: Math.max(45 * 1000, triggerIntervalSeconds * 4 * 1000),
    maxSensorSpreadMs: Math.max(25 * 1000, Math.round(triggerIntervalSeconds * 2.5 * 1000)),
    reliableConfidence: 0.7
};

const gridReading = readSensor("sensor.smartmeter_keller_sml_watt_summe");
const batteryDischargeReading = readSensor("sensor.solarflow_800_pro_output_home_power");
const solarPrimaryReading = readSensor("sensor.wechselrichter_ac_leistung");
const solarSecondaryReading = readSensor("sensor.hoymiles600_power");
const batteryChargeReading = readSensor("sensor.solarflow_800_pro_grid_input_power");

const demandTimingReadings = [
    gridReading,
    batteryDischargeReading,
    solarPrimaryReading,
    solarSecondaryReading,
    batteryChargeReading
];
const solarTimingReadings = [solarPrimaryReading, solarSecondaryReading];
const demandAgeStats = buildAgeStats(demandTimingReadings);
const solarAgeStats = buildAgeStats(solarTimingReadings);

const currentDemandRaw =
    gridReading.value +
    batteryDischargeReading.value +
    solarPrimaryReading.value +
    solarSecondaryReading.value -
    batteryChargeReading.value;
const currentSolarRaw = solarPrimaryReading.value + solarSecondaryReading.value;

let lastReliableDemand = context.get("lastReliableDemand");
if (!Number.isFinite(lastReliableDemand)) {
    lastReliableDemand = Math.max(0, currentDemandRaw);
}
let lastReliableSolar = context.get("lastReliableSolar");
if (!Number.isFinite(lastReliableSolar)) {
    lastReliableSolar = Math.max(0, currentSolarRaw);
}

const demandConfidence = calculateConfidence(
    demandAgeStats,
    timingThresholds,
    currentDemandRaw < 0
);
const solarConfidence = calculateConfidence(solarAgeStats, timingThresholds);

const currentDemandEstimate = Math.max(
    0,
    blendWithFallback(Math.max(0, currentDemandRaw), lastReliableDemand, demandConfidence)
);
const currentSolarEstimate = Math.max(
    0,
    blendWithFallback(currentSolarRaw, lastReliableSolar, solarConfidence)
);

if (demandConfidence >= timingThresholds.reliableConfidence && currentDemandRaw >= 0) {
    lastReliableDemand = currentDemandEstimate;
    context.set("lastReliableDemand", lastReliableDemand);
}
if (solarConfidence >= timingThresholds.reliableConfidence) {
    lastReliableSolar = currentSolarEstimate;
    context.set("lastReliableSolar", lastReliableSolar);
}

// 2. Manage 5-minute history based on the configured trigger interval
let history = context.get("demandHistory") || [];
history.push(currentDemandEstimate);
while (history.length > historySamples) history.shift();
context.set("demandHistory", history);

let solarHistory = context.get("solarHistory") || [];
solarHistory.push(currentSolarEstimate);
while (solarHistory.length > historySamples) solarHistory.shift();
context.set("solarHistory", solarHistory);

// 3. Calculate Average
const averageSolar =
    solarHistory.reduce((sum, value) => sum + value, 0) / Math.max(1, solarHistory.length);

// 4. Calculate Median (P50)
const sorted = [...history].sort((a, b) => a - b);
const lowMiddle = Math.floor((sorted.length - 1) / 2);
const highMiddle = Math.ceil((sorted.length - 1) / 2);
const medianDemand = (sorted[lowMiddle] + sorted[highMiddle]) / 2;

// 5. ASYMMETRIC LOGIC
const defensiveTarget = Math.min(medianDemand, currentDemandEstimate);
const proactiveSolar = currentSolarEstimate;

// 6. THE "CONTINUOUS FLOW" BIAS
const flowBias = proactiveSolar > 50 ? 20 : 0;
const snapshotLagging =
    currentDemandRaw < 0 ||
    (demandAgeStats.spreadMs !== null &&
        demandAgeStats.spreadMs > timingThresholds.maxSensorSpreadMs) ||
    (demandAgeStats.maxAgeMs !== null && demandAgeStats.maxAgeMs > timingThresholds.maxSensorAgeMs);

node.status({
    fill: snapshotLagging ? "yellow" : "blue",
    shape: snapshotLagging ? "ring" : "dot",
    text: `Solar: ${Math.round(proactiveSolar)}W | Demand: ${Math.round(defensiveTarget)}W | sync ${Math.round(
        demandConfidence * 100
    )}%`
});

msg.adjustment.defensiveTarget = Math.round(defensiveTarget - flowBias);
msg.adjustment.currentDemandRaw = Math.round(currentDemandRaw);
msg.adjustment.currentDemandEstimate = Math.round(currentDemandEstimate);
msg.adjustment.demandConfidence = Math.round(demandConfidence * 100) / 100;
msg.adjustment.solarPower = Math.round(proactiveSolar);
msg.adjustment.solarRawPower = Math.round(currentSolarRaw);
msg.adjustment.solarConfidence = Math.round(solarConfidence * 100) / 100;
msg.adjustment.solarAveragePower = Math.round(averageSolar);
msg.adjustment.sensorTiming = {
    demandAgeSpreadMs: demandAgeStats.spreadMs,
    demandMaxAgeMs: demandAgeStats.maxAgeMs,
    solarAgeSpreadMs: solarAgeStats.spreadMs,
    solarMaxAgeMs: solarAgeStats.maxAgeMs,
    snapshotLagging
};
msg.meta.sensorTiming = {
    thresholds: timingThresholds,
    demand: {
        confidence: Math.round(demandConfidence * 100) / 100,
        currentRaw: Math.round(currentDemandRaw),
        currentEstimate: Math.round(currentDemandEstimate),
        minAgeMs: demandAgeStats.minAgeMs,
        maxAgeMs: demandAgeStats.maxAgeMs,
        spreadMs: demandAgeStats.spreadMs,
        sensors: {
            grid: gridReading,
            batteryDischarge: batteryDischargeReading,
            solarPrimary: solarPrimaryReading,
            solarSecondary: solarSecondaryReading,
            batteryCharge: batteryChargeReading
        }
    },
    solar: {
        confidence: Math.round(solarConfidence * 100) / 100,
        currentRaw: Math.round(currentSolarRaw),
        currentEstimate: Math.round(currentSolarEstimate),
        minAgeMs: solarAgeStats.minAgeMs,
        maxAgeMs: solarAgeStats.maxAgeMs,
        spreadMs: solarAgeStats.spreadMs,
        sensors: {
            solarPrimary: solarPrimaryReading,
            solarSecondary: solarSecondaryReading
        }
    }
};
msg.meta.history = {
    windowSeconds: historyWindowSeconds,
    triggerIntervalSeconds: triggerIntervalSeconds,
    triggerIntervalMs: triggerIntervalSeconds * 1000,
    samples: historySamples
};
return msg;

const map = msg.payload;

// 1. DATA EXTRACTION
const availableWh = (parseFloat(map["sensor.solarflow_800_pro_available_kwh"]?.state) || 0) * 1000;

// 2. NEXT HOUR FORECAST (Wh expected in the next 60 mins)
const nextH1 = parseFloat(map["sensor.energy_next_hour"]?.state) || 0;
const nextH2 = parseFloat(map["sensor.energy_next_hour_2"]?.state) || 0;
const totalNextHourWh = nextH1 + nextH2;

// 3. TIME CALCULATION
const now = new Date().getTime();
const sunrise = new Date(map["sun.sun"]?.attributes?.next_rising).getTime();

// 4. DYNAMIC WINDOW ADJUSTMENT
let hoursToUsableSolar = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));

// If the Next Hour forecast is already > 50Wh, the sun is effectively "up"
// for the battery logic, even if the clock says it's early.
if (totalNextHourWh > 100) {
    // Sun is strong! Shorten the window to 1 hour to empty the battery faster.
    hoursToUsableSolar = 1.0;
} else if (totalNextHourWh > 20) {
    // Sun is starting to peek through.
    hoursToUsableSolar = Math.min(hoursToUsableSolar, 2.0);
}

// Handle edge case: If it's 2 AM and sunrise is 6 AM, hoursToSunrise = 4.
// If sunrise has already passed or is invalid, default to a small number to avoid division by zero.
// Calculate hours only if we have a valid date
let hoursToSunrise = 0.5; // Default safety
if (!isNaN(sunrise)) {
    // Math.max ensures we don't get negative numbers if sunrise just happened
    hoursToSunrise = Math.max(0.5, (sunrise - now) / (1000 * 60 * 60));
}

// 3. CALCULATION
const usableWh = Math.max(0, availableWh);
const forcedRate = Math.round(usableWh / hoursToUsableSolar);

// 4. PASS IT FORWARD
msg.adjustment.forcedRate = forcedRate;
msg.adjustment.hoursToSunrise = hoursToSunrise.toFixed(1);
msg.adjustment.nextHourSolar = totalNextHourWh;

node.status({ fill: "blue", shape: "ring", text: `Budget: forced ${forcedRate}W until sunrise` });

return msg;

// 1. DATA RETRIEVAL (Using the Map in the input message)
const ha = msg.payload;

// Get numeric values from Home Assistant collection (handling "unavailable" with || 0)
const gridPower = parseFloat(ha["sensor.smartmeter_keller_sml_watt_summe"]?.state) || 0;
const currentBatteryOut = parseFloat(ha["sensor.solarflow_800_pro_output_home_power"]?.state) || 0;
const calculatedDemand = msg.adjustment.defensiveTarget;
const smoothedSolarPower = msg.adjustment.solarPower;
const forcedDischarge = msg.adjustment.forcedRate;

// 2. CONFIGURATION (Based on safety buffer strategy)
// this addresses the "Moving Target" problem with huge latencies of smart meter and battery chargine changes:
//   1. The Deadband(deadband = 75): This is your Cycle - Killer.
//                                   It stops the battery from chasing the "ghosts" of small appliances.
//                                   If your fridge compressor flickers, the battery ignores it.
//
//   2. The Safety Buffer(-30): By aiming for a 30W import, you create a "cushion."
//                              When a cloud disappears and solar spikes, you have 30W of "room" before
//                              starting to feed-in into public grid.
//
//   3. The EMA(alpha = 0.9): This solves the 50s latency of smart meter and battery.
//                            Instead of jumping to a new value every 20s (init trigger) and
//                            overshooting, the battery "slides" toward the new value. This reduces the
//                            chemical stress on the LiFePO4 cells.

const targetBuffer = -50; // Aim for 50W import to prevent feed-in
const deadband = 50; // Ignore fluctuations smaller than 50W
const alpha = 0.3; // EMA Smoothing factor (0.1 = very slow, 0.9 = very fast)

// 3. CALCULATION
// calculated Demand is the brutto demand of power, solar power the generated and usable power.
// default expects, that there is more solar power than demand,
// e.g. 10W (solar) - 300W (demand) - (-30) = -260W to discharge
//       0W (solar) - 50W (demand) - (-30) = -20W to discharge
//     100W (solar) - 200W (demand) - (-30) = -70W to discharge
//       0W (solar) - 200W (demand) - (-30) = -170W to discharge
//       1W (solar) - 201W (demand) - (-30) = -170W to discharge
//       0W (solar) - (-50)W (demand) - (-30) = 80W to adjust or even stop discharging (discharging is at least 50W)
let requiredChange = smoothedSolarPower - calculatedDemand - targetBuffer;

// 4. THE CYCLE GUARD (Dynamic Deadband)
// If the requiredChange is small AND we aren't "exporting", stay still to save battery cycles
if (Math.abs(requiredChange) < deadband && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Done (deadband) - Stable power - finish (calculated change is ${Math.round(requiredChange)}W, grid power: ${Math.round(gridPower)}W)`
    });
    return null; // Stop the message here; no command sent to inverter
}

// 5. EMA SMOOTHING (The "Lag Compensator")
let lastCommand = context.get("lastCommand") || 0;
let rawCommand = requiredChange * -1; // invert to represent the power gap required from battery

if (rawCommand < 0 && currentBatteryOut > 0) {
    // demand is larger than solar power but still solar power available
    rawCommand = (requiredChange - targetBuffer - currentBatteryOut) * -1; // 80W - 30 - 60 = -10 -> reduce discharging before stopping
}

// Apply Exponential Moving Average
let smoothedCommand = rawCommand * alpha + lastCommand * (1 - alpha);

// 5. THE ZERO-EXPORT DEFENSE (The "No-Penalty" Guard)
// --> EMERGENCY BRAKE
if (gridPower < 0) {
    smoothedCommand = Math.max(0, currentBatteryOut + gridPower + targetBuffer);
}

smoothedCommand = Math.min(smoothedCommand, forcedDischarge * 2.5);

// Only output if the command actually changed significantly (e.g., > 5W)
if (Math.abs(smoothedCommand - lastCommand) < 5 && gridPower > 0 && currentBatteryOut == 0) {
    node.status({
        fill: "green",
        shape: "dot",
        text: `Idle (deadband) - Hardly changed power - finish: ${Math.round(smoothedCommand)}W, grid Power ${gridPower}W`
    });
    return null;
}

// 6. FINAL OUTPUT & PERSISTENCE
context.set("lastCommand", smoothedCommand);

// Store the results in their own property, keeping the map safe
msg.adjustment = {
    command: Math.round(smoothedCommand),
    requiredChange: requiredChange, // The raw error before smoothing
    isStable: Math.abs(requiredChange) < deadband,
    grid: gridPower
};

// Now msg.payload still contains 31 entities,
// and msg.adjustment contains this logic results.
node.status({
    fill: "green",
    shape: "dot",
    text: `Calculated Power (smoothed): ${Math.round(smoothedCommand)}W`
});
return msg;
